SELECT count(*) FROM movie_keyword, title, keyword, cast_info, role_type, char_name, name WHERE movie_keyword.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND cast_info.movie_id = title.id AND cast_info.role_id = role_type.id AND cast_info.person_role_id = char_name.id AND cast_info.person_id = name.id;